h":"450","height":"445"},"image":{"@id":"https://roadtostudy.com/#logo"}},{"@type":"WebSite","@id":"https://roadtostudy.com/#website","url":"https://roadtostudy.com","name":"Road to Study - Turkey University Guide for Students","alternateName":"Road to Study in Turkey","publisher":{"@id":"https://roadtostudy.com/#person"},"inLanguage":"fr-FR"},{"@type":"WebPage","@id":"https://roadtostudy.com/fr/procedures-en-cas-de-perte-dobjets-ou-de-documents-en-turquie/#webpage","url":"https://roadtostudy.com/fr/procedures-en-cas-de-perte-dobjets-ou-de-documents-en-turquie/","name":"Procédures en cas de perte d&#039;objets ou de documents en Turquie - RoadtoStudy","datePublished":"2026-03-02T09:00:00+03:00","dateModified":"2026-03-06T12:12:17+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"inLanguage":"fr-FR"},{"@type":"Person","@id":"https://roadtostudy.com/fr/author/murat/","name":"Murat","url":"https://roadtostudy.com/fr/author/murat/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","caption":"Murat","inLanguage":"fr-FR"}},{"@type":"BlogPosting","headline":"Procédures en cas de perte d&#039;objets ou de documents en Turquie - RoadtoStudy","datePublished":"2026-03-02T09:00:00+03:00","dateModified":"2026-03-06T12:12:17+03:00","articleSection":"Vie étudiante et Voyages","author":{"@id":"https://roadtostudy.com/fr/author/murat/","name":"Murat"},"publisher":{"@id":"https://roadtostudy.com/#person"},"description":"Découvrez les procédures à suivre pour retrouver vos objets perdus. Notre guide étape par étape vous aidera à récupérer rapidement vos documents égarés !","name":"Procédures en cas de perte d&#039;objets ou de documents en Turquie - RoadtoStudy","@id":"https://roadtostudy.com/fr/procedures-en-cas-de-perte-dobjets-ou-de-