UPDATE "ec_posts" SET "source_seo" = '{"title":"Pengalaman Budaya yang Jarang Diketahui di Turki - RoadtoStudy","description":"Mulailah perjalanan yang penuh dengan pengalaman budaya tak terjamah di Turki. Klik di sini untuk mengenal berbagai budaya yang berbeda dan memperkaya pengalaman studi Anda!","robots":"follow, index, max-snippet:-1, max-video-preview:-1, max-image-preview:large","ogTitle":"Pengalaman Budaya yang Jarang Diketahui di Turki - RoadtoStudy","ogDescription":"Mulailah perjalanan yang penuh dengan pengalaman budaya tak terjamah di Turki. Klik di sini untuk mengenal berbagai budaya yang berbeda dan memperkaya pengalaman studi Anda!","ogImage":null,"twitterCard":"summary_large_image","twitterTitle":"Pengalaman Budaya yang Jarang Diketahui di Turki - RoadtoStudy","twitterDescription":"Mulailah perjalanan yang penuh dengan pengalaman budaya tak terjamah di Turki. Klik di sini untuk mengenal berbagai budaya yang berbeda dan memperkaya pengalaman studi Anda!","canonicalPath":"/id/pengalaman-budaya-yang-jarang-diketahui-di-turki/","hreflang":[{"hreflang":"tr","href":"/turkiyede-az-bilinen-kulturel-deneyimler/"},{"hreflang":"en","href":"/en/lesser-known-cultural-experiences-in-turkey/"},{"hreflang":"id","href":"/id/pengalaman-budaya-yang-jarang-diketahui-di-turki/"},{"hreflang":"fr","href":"/fr/experiences-culturelles-meconnues-en-turquie/"}],"jsonLd":[{"@context":"https://schema.org","@graph":[{"@type":["Organization","Person"],"@id":"https://roadtostudy.com/#person","name":"Road to Study - Turkey University Guide for Students","url":"https://roadtostudy.com","logo":{"@type":"ImageObject","@id":"https://roadtostudy.com/#logo","url":"https://roadtostudy.com/wp-content/uploads/2025/02/Kare-Logo-e1740739634958.png","contentUrl":"https://roadtostudy.com/wp-content/uploads/2025/02/Kare-Logo-e1740739634958.png","caption":"Road to Study - Turkey University Guide for Students","inLanguage":"id","width":"450","height":"445"},"image":{"@id":"https://roadtostudy.com/